class Solution:
    def maxPalindromes(self, s, k):
        n = len(s)
        is_pal = [[False] * n for _ in range(n)]
        for i in range(n):
            is_pal[i][i] = True
        for length in range(2, n + 1):
            for i in range(0, n - length + 1):
                j = i + length - 1
                if s[i] == s[j]:
                    if length == 2:
                        is_pal[i][j] = True
                    else:
                        is_pal[i][j] = is_pal[i + 1][j - 1]
        dp = [0] * (n + 1)
        for i in range(1, n + 1):
            dp[i] = dp[i - 1]
            for start in range(0, i - k + 1):
                if is_pal[start][i - 1] and (i - start) >= k:
                    dp[i] = max(dp[i], dp[start] + 1)
        return dp[n]

