class Solution:
    def maxPalindromes(self, s, k):
        n = len(s)
        count = 0
        cursor = 0
        def grows(l, r):
            while l >= 0 and r < n and s[l] == s[r]:
                if r - l + 1 >= k and l >= cursor:
                    return r
                l -= 1
                r += 1
            return -1
        for center in range(n):
            taken = -1
            r1 = grows(center, center)
            r2 = grows(center, center + 1)
            cands = [x for x in (r1, r2) if x != -1]
            if cands:
                taken = min(cands)
            if taken != -1:
                count += 1
                cursor = taken + 1
        return count

