var maxPalindromes = function(s, k) {
    const n = s.length;
    let count = 0;
    let cursor = 0;
    const grows = (l, r) => {
        while (l >= 0 && r < n && s[l] === s[r]) {
            if (r - l + 1 >= k && l >= cursor) return r;
            l--; r++;
        }
        return -1;
    };
    for (let center = 0; center < n; center++) {
        const r1 = grows(center, center);
        const r2 = grows(center, center + 1);
        const cands = [r1, r2].filter(x => x !== -1);
        let taken = -1;
        if (cands.length) taken = Math.min(...cands);
        if (taken !== -1) {
            count++;
            cursor = taken + 1;
        }
    }
    return count;
};
